mapper.insert:
MERGE INTO TBL_REFRESHTOKEN USING DUAL ON (EMAIL = #{email})
WHEN MATCHED THEN UPDATE SET RT_VALUE = #{rtValue}
WHEN NOT MATCHED THEN INSERT (EMAIL, RT_VALUE) VALUES (#{email}, #{rtValue})
